{
  "name": "DenaliCare",
  "eligibility": {
    "age": null,
    "income_limits": "For a single applicant in 2026: under $2,982 per month. Limits vary by marital status, program (e.g., Nursing Home Medicaid, HCBS Waivers, ABD Medicaid), and household size; no full table provided in sources. ABD Medicaid has separate income limits.[1][2]",
    "asset_limits": "For a single applicant: $2,000 or less in countable assets. Countable assets typically include bank accounts, stocks, bonds (exemptions often include primary home, one vehicle, personal belongings, burial plots; spousal protections apply if married). Varies by marital status and program.[1][2]",
    "other_requirements": ["Alaska resident", "Nursing Facility Level of Care (NFLOC) for Nursing Home Medicaid and HCBS Waivers: requires assistance with Activities of Daily Living (ADLs: mobility, bathing, dressing, eating, toileting) and/or Instrumental ADLs (IADLs: cleaning, cooking, shopping, bills), plus cognitive/behavioral issues", "Functional/medical need for long-term care", "Age 65+ for certain elderly pathways, but not strictly required for all programs"][1][2]
  },
  "benefits": {
    "type": "service",
    "value": "Long-term care services via Nursing Home Medicaid, Home and Community Based Services (HCBS) Waivers, or Aged, Blind, and Disabled (ABD) Medicaid. Specific services include nursing home care, HCBS waiver supports (e.g., home modifications if unable to live safely at home without them), and regular Medicaid long-term care (functional ADL need, no NFLOC required). No specific dollar amounts or hours stated.[1][2]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Online: Alaska’s Resource for Integrated Eligibility Services (ARIES) Self-Service Portal", "Phone: Virtual Contact Center at 800-478-7778", "Mail/In-person: Submit Application for Services to Division of Public Assistance Office", "Assistance: Division of Senior and Disability Services office or local Aging and Disability Resource Center (ADRC)"][2],
    "processing_time": "Not specified in sources",
    "waitlist": null,
    "forms": ["Application for Services (GEN 50C)"][2][6],
    "documents": ["Proof of income, assets, residency, medical/functional need documentation (e.g., for NFLOC assessment); specifics vary by program"][1][2]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Application process may vary by program; contact local Division of Public Assistance Office or ADRC for regional assistance. No specific wait times or provider differences noted.[2]",
    "offices_or_providers": ["Division of Public Assistance Offices", "Division of Senior and Disability Services offices", "Local Aging and Disability Resource Centers (ADRCs)"]
  },
  "official_source": "https://health.alaska.gov/ (Medicaid page; specific DenaliCare long-term care details via ARIES portal or 800-478-7778)",
  "gotchas": ["DenaliCare for elderly long-term care is distinct from Denali KidCare (CHIP for kids/pregnant women); sources often conflate", "Not meeting limits initially does not preclude eligibility (e.g., spousal impoverishment, planning options for 65+)", "Requires NFLOC for key programs; some benefits need extra criteria (e.g., home mods)", "Financial criteria vary by marital status/program; ABD Medicaid separate", "Functional assessment determines NFLOC"][1][2][4],
  "data_shape_notes": "Part of Alaska Medicaid long-term care (Nursing Home, HCBS Waivers, ABD); eligibility varies by marital status/program with NFLOC requirement; asset/income strict for singles but spousal protections; no full income table or processing times available"
}

{
  "name": "Meals on Wheels (Alaska Senior Nutrition Programs)",
  "eligibility": {
    "age": 60,
    "income_limits": "No income limits or tests; income is not a factor in eligibility across programs[4][8].",
    "asset_limits": "No asset limits mentioned or applicable.",
    "other_requirements": ["Homebound or physically limited in ability to carry out activities of daily living, or have mobility challenges making shopping, meal preparation, or socialization difficult[1][2][4][8]", "Reside in a program delivery zone or service area[1]", "For home-delivered meals, often requires doctor's note stating homebound or disabled (self or spouse)[8]", "For congregate meals, complete a client profile at the meal site[4]"]
  },
  "benefits": {
    "type": "service",
    "value": "Home-delivered hot meals (typically 5 days/week, with frozen meals for weekends/holidays); congregate hot nutritious lunches at senior centers (Monday-Friday); each meal provides ~1/3 of daily nutritional requirements; special dietary meals with prescription; socialization opportunities at congregate sites[3][4][8]",
    "varies_by": "region"
  },
  "application": {
    "methods": ["Contact local provider or Area Agency on Aging by phone (e.g., Salvation Army Anchorage: (907) 349-0613[4]; Fairbanks Senior Center: (907) 452-1735[5]; North Slope: via Senior Program application[8])", "Complete specific forms: MOW and Nutritional forms (Fairbanks)[5]; client profile at meal site (congregate)[4]; SESS application for Southeast Alaska[9]", "In-person at senior centers or meal sites (e.g., Anchorage: 9131 Centennial Circle[4]; Wasilla: 1301 S Century Cir[7]; 12 SESS centers in Southeast[9])", "Initial assessment of needs, health, mobility, dietary restrictions[1]"],
    "processing_time": "Varies; some within a week, longer with waitlists[1]",
    "waitlist": "Possible depending on local program demand[1]",
    "forms": ["MOW and Nutritional forms (Fairbanks)[5]", "Client profile (congregate sites)[4]", "Senior Nutrition Program application (Southeast Alaska)[9]", "General application and needs assessment required by most[2]"],
    "documents": ["Proof of age, residence, medical information (e.g., doctor's note for homebound status)[1][8]", "Dietary prescription for special meals[3]", "Referral letter from doctor or social worker (some providers)[2]"]
  },
  "geography": {
    "statewide": false,
    "restrictions": "Must live in local delivery zone or service area of provider[1]",
    "regional_variations": "Administered by local providers/senior centers with different offices, contacts, and forms; e.g., Anchorage (Salvation Army), Fairbanks (Senior Center), Wasilla, North Slope Borough (requires doctor's note), Southeast Alaska (SESS 12 centers); congregate vs. home-delivered availability varies[4][5][7][8][9]",
    "offices_or_providers": ["Salvation Army, Anchorage (9131 Centennial Circle)[4]", "Fairbanks Senior Center[5]", "Wasilla (1301 S Century Cir)[7]", "North Slope Borough Senior Program[8]", "SESS (12 centers in Southeast Alaska)[9]"]
  },
  "official_source": "https://health.alaska.gov/ (Alaska DHSS for senior nutrition oversight); local providers via https://www.mealsonwheelsamerica.org/find-meals-and-services/[2][3]",
  "gotchas": ["Not statewide—must confirm local provider and delivery zone first[1]", "Home-delivered often requires proof of homebound status via doctor's note, unlike congregate meals[8]", "Fees may apply as suggested donation, sliding scale, or free based on location/income ability (not eligibility barrier)[2]", "Car ownership or ability to leave home easily may disqualify from home delivery[1]", "Separate applications for congregate vs. home-delivered; spouses/dependents sometimes eligible[1]"],
  "data_shape_notes": "Decentralized by region with local providers/senior centers; no statewide income/asset test; eligibility emphasizes homebound/mobility need over finances; varies by urban (Anchorage/Fairbanks) vs. rural/borough (North Slope/Southeast)"
}

{
  "name": "Senior Community Service Employment Program (SCSEP)",
  "eligibility": {
    "age": 55,
    "income_limits": "Family income no more than 125% of the federal poverty level. Exact dollar amounts vary annually by household size and are set by the U.S. Department of Health & Human Services poverty guidelines (e.g., for 2024, approximately $19,725 for 1 person, $26,630 for 2, $33,535 for 3, increasing by ~$6,905 per additional person; check current HHS guidelines for precise figures as they update yearly)[3][7]",
    "asset_limits": null,
    "other_requirements": ["Unemployed", "Low employment prospects", "U.S. citizen or authorized to work", "Priority for veterans/qualified spouses, age 65+, disabled, low literacy/limited English, rural residents, homeless/at risk, or prior American Job Center users"][3]
  },
  "benefits": {
    "type": "employment",
    "value": "Part-time paid community service job training (average 20 hours/week at highest of federal/state/local minimum wage); job skills training, job search assistance, placement into unsubsidized employment; supportive services",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Phone: Contact Southeast Regional Resource Center (SERRC) at (907) 524-9474 or Alaska Department of Labor and Workforce Development (DOLWD) local offices via 1-888-448-3528", "In-person: Alaska Job Centers or SERRC offices (e.g., Juneau for MASST)", "Website: https://serrc.org/masst/ for MASST (Alaska's SCSEP)"],
    "processing_time": null,
    "waitlist": "Likely due to limited slots; varies by region and funding",
    "forms": ["Alaska SCSEP Durational Limits Form (provided at enrollment)"],
    "documents": ["Proof of age (ID/birth certificate)", "Proof of income (tax returns, pay stubs, benefit statements)", "Proof of unemployment", "Social Security number", "Veteran status if applicable"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Administered statewide by DOLWD and subrecipients like SERRC (MASST); placements via regional coordinators with nonprofits/government/Native organizations; rural priority may affect availability",
    "offices_or_providers": ["SERRC (https://serrc.org/masst/)", "Alaska DOLWD Employment & Training Services", "Alaska Job Center Network"]
  },
  "official_source": "https://labor.state.ak.us/dets/ or https://serrc.org/masst/",
  "gotchas": ["Maximum 48 months lifetime participation (no exceptions, breaks excluded)[2]", "Part-time only (not full-time wage replacement)", "Must transition to unsubsidized job; not guaranteed", "Priority tiers may delay entry for non-priority applicants", "Income calculated at 125% FPL for entire family, not individual"],
  "data_shape_notes": "Alaska-specific name MASST; administered by DOLWD/SERRC; 48-month hard cap; priority-based enrollment; statewide but regional coordinators/hosts; income at 125% FPL family level"
}

{
  "name": "Alaska Legal Services Corporation (Senior Legal Aid)",
  "eligibility": {
    "age": 60,
    "income_limits": "For seniors (60+), assistance may be provided without regard to income, with priority to those in social or economic need. General program income limit is at or below 125% of Federal Poverty Guidelines for Alaska (most applicants qualify here, but seniors have flexibility):\n|Household Size|Yearly|Monthly|Weekly|\n|--|--|--|--|\n|1|$24,438|$2,037|$470|\n|2|$33,038|$2,753|$635|\n|3|$41,638|$3,470|$801|\n|4|$50,238|$4,187|$966|\n|5|$58,838|$4,903|$1,132|\n|6|$67,438|$5,620|$1,297|\n|7|$76,038|$6,337|$1,462|\n|8|$84,638|$7,053|$1,628|\n|Each additional|$8,600|$717|$165|[1][2]",
    "asset_limits": "Assets are considered in the eligibility interview, but no specific dollar limits or exemptions detailed.[6][7]",
    "other_requirements": ["Alaska resident", "Civil legal issue (no criminal cases)", "No conflicts of interest (prior representation of opposing party)", "Case must align with office priorities", "Priority for greatest financial or personal need"][1][2][7]
  },
  "benefits": {
    "type": "service",
    "value": "Legal assistance and advice, court/administrative representation, referrals, community education/training via clinics/outreach. Specific senior areas: income maintenance (Alaska Senior Assistance Program, Social Security, SSI, Adult Public Assistance, Food Stamps), housing (landlord/tenant, public housing, assisted living, nursing homes), health care (Medicaid, Medicare, Long-Term Care, PCA program), guardianship defense, wills, living wills, estates, powers of attorney. No fixed dollar amounts or hours; case-by-case based on resources.[2][3][7]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": [
      "Online: ALSC Online Eligibility Interview at https://www.alsc-law.org/intake/[6][8]",
      "Phone: Toll-free statewide intake line at 1-888-478-2572[5][6][7][8]",
      "Mail/In-person: Paper application at nearest ALSC office (available in English, Samoan, Tagalog, Spanish, German, Russian); e.g., Juneau Office: 8711 Teal Street, Suite 203, Juneau, AK 99801[5][10]"
    ],
    "processing_time": "Intake specialist contacts within two business days after online submission[6]",
    "waitlist": "No guaranteed acceptance or timeline due to limited resources; case staffing attempted if eligible, but not all cases accepted[5][6][7][8]",
    "forms": ["ALSC Online Eligibility Interview", "Paper Application for Services (office-specific)"][5][6],
    "documents": ["Information on legal issue(s), gross household income, assets, phone/email for contact. Be prepared with all papers about the legal problem. No specific list mandated, but complete all application sections for eligibility determination."][6][7]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Alaska residents only",
    "regional_variations": "Priorities set by each office; contact nearest office for local details. Served 147 communities statewide, but resource limits may cause variations in acceptance/wait times.[1][3][10]",
    "offices_or_providers": ["Multiple offices, e.g., Juneau Office: 8711 Teal Street, Suite 203, Juneau, AK 99801, Phone: 907-586-6425, Toll Free: 1-800-789-6426[10]"]
  },
  "official_source": "https://www.alsc-law.org/elder-advocacy/",
  "gotchas": [
    "Seniors 60+ may qualify without strict income limits, but priority to those in need; not automatic[2]",
    "No guarantee of acceptance due to limited resources and case priorities set by offices/board[1][5][6][7][8]",
    "No criminal cases, personal injury, accidents, or wrongful death[7][8]",
    "Conflicts of interest lead to referral elsewhere[1]",
    "Must complete full application (income/assets/legal issue) for proper review[5][6][7]"
  ],
  "data_shape_notes": "Seniors (60+) have income flexibility unlike general 125% FPL limit; services case-priority based with office variations; statewide but resource-constrained"
}
